const csvRaw = $json.data ?? $json.body ?? $json;
const text = (typeof csvRaw === "string") ? csvRaw : JSON.stringify(csvRaw);

const lines = text.split(/\r?\n/).map(line => line.trim()).filter(Boolean);
const headers = lines[0].split(",").map(h => h.trim());

const investimentos = lines.slice(1).map(line => {
  const cols = line.split(",").map(c => c.trim());
  const obj = {};
  headers.forEach((h, i) => obj[h] = cols[i] ?? "");

  obj.minimo = Number(String(obj.minimo).replace(/[^\d]/g, "")) || 0;

  return obj;
});

return [{ json: { investimentos } }];

const item = $input.first().json;

const clientes = item.body?.clientes ?? item.clientes ?? [];
const investimentos = item.investimentos ?? [];

function limparTexto(valor) {
  return String(valor ?? "")
    .trim()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");
}

function saldoParaNumero(valor) {
  return Number(
    String(valor ?? "")
      .replace("R$", "")
      .replace(/\./g, "")
      .replace(",", ".")
      .trim()
  ) || 0;
}

function minimoParaNumero(valor) {
  return Number(
    String(valor ?? "")
      .replace("R$", "")
      .replace(/\./g, "")
      .replace(",", ".")
      .replace(/[^\d.]/g, "")
      .trim()
  ) || 0;
}

function rentabilidadeParaNumero(valor) {
  return Number(
    String(valor ?? "")
      .replace("%", "")
      .replace(",", ".")
      .trim()
  ) || 0;
}

function formatarMoeda(valor) {
  return valor.toLocaleString("pt-BR", {
    style: "currency",
    currency: "BRL"
  });
}

const recomendacoes = clientes.map(cliente => {
  const nome = cliente.nome;
  const email = cliente.email;
  const perfilCliente = cliente.perfil;
  const saldoCliente = saldoParaNumero(cliente.saldo);

  const opcoesCompativeis = investimentos
    .filter(investimento => {
      const mesmoPerfil =
        limparTexto(investimento.perfil) === limparTexto(perfilCliente);

      const valorMinimo = minimoParaNumero(investimento.minimo);

      return mesmoPerfil && saldoCliente >= valorMinimo;
    })
    .sort((a, b) => {
      return (
        rentabilidadeParaNumero(b.rentabilidade) -
        rentabilidadeParaNumero(a.rentabilidade)
      );
    });

  const melhorOpcao = opcoesCompativeis[0];

  let mensagem;

  if (melhorOpcao) {
    mensagem =
      `Olá, ${nome}!\n\n` +
      `Com base no seu perfil de investidor (${perfilCliente}) e no seu saldo disponível de ${formatarMoeda(saldoCliente)}, ` +
      `identificamos uma opção de investimento compatível com o seu cadastro.\n\n` +
      `Recomendação principal:\n` +
      `Produto: ${melhorOpcao.produto}\n` +
      `Perfil indicado: ${melhorOpcao.perfil}\n` +
      `Valor mínimo: ${formatarMoeda(minimoParaNumero(melhorOpcao.minimo))}\n` +
      `Rentabilidade estimada: ${melhorOpcao.rentabilidade}\n\n` +
      `Essa recomendação foi selecionada porque respeita o seu perfil de risco e está dentro do saldo disponível informado.`;
  } else {
    mensagem =
      `Olá, ${nome}!\n\n` +
      `Com base no seu perfil de investidor (${perfilCliente}) e no seu saldo disponível de ${formatarMoeda(saldoCliente)}, ` +
      `não encontramos, no momento, uma opção de investimento compatível com os critérios disponíveis.\n\n` +
      `Isso pode ocorrer quando o saldo informado é inferior ao valor mínimo exigido pelos produtos associados ao seu perfil.`;
  }

  return {
    json: {
      nome,
      email,
      perfil: perfilCliente,
      saldo: saldoCliente,
      recomendacao: melhorOpcao ?? null,
      quantidadeOpcoesDisponiveis: opcoesCompativeis.length,
      mensagem
    }
  };
});

return recomendacoes;

const items = $input.all();

function limparTexto(valor) {
  return String(valor ?? "").trim();
}

function formatarMoeda(valor) {
  const numero = Number(valor) || 0;

  return numero.toLocaleString("pt-BR", {
    style: "currency",
    currency: "BRL"
  });
}

function formatarDataHora() {
  return new Date().toLocaleString("pt-BR", {
    timeZone: "America/Sao_Paulo",
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit"
  });
}

function formatarRentabilidade(valor) {
  const texto = limparTexto(valor);

  if (!texto) {
    return "Não informada";
  }

  return texto.includes("%") ? texto : `${texto}%`;
}

function formatarValorMinimo(valor) {
  const numero = Number(valor) || 0;
  return formatarMoeda(numero);
}

const dataProcessamento = formatarDataHora();

return items.map(item => {
  const dados = item.json;

  const nome = limparTexto(dados.nome);
  const email = limparTexto(dados.email);
  const perfil = limparTexto(dados.perfil);
  const saldo = Number(dados.saldo) || 0;
  const saldoFormatado = formatarMoeda(saldo);

  const recomendacao = dados.recomendacao;
  const possuiRecomendacao = recomendacao !== null && recomendacao !== undefined;

  let produto = "Nenhum produto disponível";
