  let valorMinimo = "Não aplicável";
  let rentabilidade = "Não aplicável";
  let status = "Sem recomendação disponível";
  let resumoRecomendacao = "";
  let mensagemFinalTexto = "";
  let mensagemFinalHtml = "";

  if (possuiRecomendacao) {
    produto = limparTexto(recomendacao.produto);
    perfilProduto = limparTexto(recomendacao.perfil);
    valorMinimo = formatarValorMinimo(recomendacao.minimo);
    rentabilidade = formatarRentabilidade(recomendacao.rentabilidade);
    status = "Recomendação gerada com sucesso";

    resumoRecomendacao =
      `Produto recomendado: ${produto}\n` +
      `Perfil do produto: ${perfilProduto}\n` +
      `Valor mínimo: ${valorMinimo}\n` +
      `Rentabilidade estimada: ${rentabilidade}`;

    mensagemFinalTexto =
      `Olá, ${nome}.\n\n` +
      `Com base no seu perfil de investidor e nas informações disponíveis, encontramos uma recomendação compatível para você.\n\n` +
      `Dados considerados:\n` +
      `Perfil do cliente: ${perfil}\n` +
      `Saldo disponível: ${saldoFormatado}\n\n` +
      `Recomendação:\n` +
      `${resumoRecomendacao}\n\n` +
      `Motivo da recomendação:\n` +
      `O produto foi selecionado porque está alinhado ao seu perfil de risco e possui valor mínimo compatível com o saldo informado.\n\n` +
      `Observação: esta recomendação foi gerada automaticamente com base nos dados disponíveis no sistema.`;

    mensagemFinalHtml =
      `<p>Olá, <strong>${nome}</strong>.</p>` +
      `<p>Com base no seu perfil de investidor e nas informações disponíveis, encontramos uma recomendação compatível para você.</p>` +
      `<p><strong>Dados considerados:</strong></p>` +
      `<ul>` +
      `<li>Perfil do cliente: ${perfil}</li>` +
      `<li>Saldo disponível: ${saldoFormatado}</li>` +
