const items = $input.all();

const NOME_NO_DADOS_ORIGINAIS = "Code in JavaScript2";

let itensOriginais = [];

try {
  itensOriginais = $items(NOME_NO_DADOS_ORIGINAIS);
} catch (error) {
  itensOriginais = [];
}

function limparTexto(valor) {
  return String(valor ?? "").trim();
}

function primeiroValor(...valores) {
  for (const valor of valores) {
    if (valor !== undefined && valor !== null && String(valor).trim() !== "") {
      return valor;
    }
  }

  return "";
}

function emailValido(email) {
  const texto = limparTexto(email);

  if (!texto) return false;

  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(texto);
}

function formatarMoeda(valor) {
  const numero = Number(valor) || 0;

  return numero.toLocaleString("pt-BR", {
    style: "currency",
    currency: "BRL"
  });
}

function parseBRL(valor) {
  if (valor === undefined || valor === null || valor === "") return 0;

  if (typeof valor === "number" && Number.isFinite(valor)) {
    return valor;
  }

  let texto = String(valor)
    .replace("R$", "")
    .replace(/\s/g, "")
    .trim();

  if (texto.includes(".") && texto.includes(",")) {
    texto = texto.replace(/\./g, "").replace(",", ".");
  } else if (texto.includes(",")) {
    texto = texto.replace(",", ".");
  } else if (/^\d{1,3}(\.\d{3})+$/.test(texto)) {
    texto = texto.replace(/\./g, "");
  }

  texto = texto.replace(/[^\d.-]/g, "");

  const numero = Number(texto);
  return Number.isFinite(numero) ? numero : 0;
}

function formatarDataHora() {
  return new Date().toLocaleString("pt-BR", {
    timeZone: "America/Sao_Paulo",
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit"
  });
}

function removerMarkdownJson(texto) {
  return String(texto ?? "")
    .replace(/```json/gi, "")
    .replace(/```/g, "")
    .trim();
}

function tentarExtrairJson(valor) {
  if (!valor) return null;

  if (typeof valor === "object") {
    return valor;
  }

  const texto = removerMarkdownJson(valor);

  try {
    return JSON.parse(texto);
  } catch (error) {
    const inicio = texto.indexOf("{");
    const fim = texto.lastIndexOf("}");

    if (inicio >= 0 && fim > inicio) {
      try {
        return JSON.parse(texto.slice(inicio, fim + 1));
      } catch (erroInterno) {
        return null;
      }
    }

    return null;
  }
}

function obterRespostaAgente(dados) {
  const candidatos = [
    dados.output,
    dados.text,
    dados.response,
    dados.result,
    dados.resultado,
    dados.message,
    dados.content,
    dados
  ];

  for (const candidato of candidatos) {
    const json = tentarExtrairJson(candidato);

    if (json && (json.subject || json.text_body || json.html_body)) {
      return json;
    }
  }

  return {};
}

function escaparHtml(valor) {
  return String(valor ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

function textoParaHtml(texto) {
  const conteudo = escaparHtml(texto);

  return `<p>${conteudo
    .replace(/\n\n/g, "</p><p>")
    .replace(/\n/g, "<br>")}</p>`;
}

const dataProcessamento = formatarDataHora();

return items.map((item, index) => {
  const dadosAtuais = item.json;
  const dadosOriginais = itensOriginais[index]?.json ?? {};

  const respostaAgente = obterRespostaAgente(dadosAtuais);

  const nome = limparTexto(primeiroValor(
    dadosOriginais.cliente?.nome,
    dadosOriginais.nome,
    dadosAtuais.cliente?.nome,
    dadosAtuais.nome
  ));

  const emailDetectado = limparTexto(primeiroValor(
    dadosOriginais.cliente?.email,
    dadosOriginais.email,
    dadosOriginais.email_to,
    dadosOriginais.envio?.destinatario,
    dadosAtuais.cliente?.email,
    dadosAtuais.email,
    dadosAtuais.email_to,
    dadosAtuais.gmail?.to
  ));

  const to = emailValido(emailDetectado) ? emailDetectado : "";

  const perfil = limparTexto(primeiroValor(
    dadosOriginais.cliente?.perfil,
    dadosOriginais.perfil,
    dadosAtuais.cliente?.perfil,
    dadosAtuais.perfil
  ));

  const saldoOriginal = primeiroValor(
    dadosOriginais.cliente?.saldo,
    dadosOriginais.cliente?.saldo_formatado,
    dadosOriginais.saldo,
    dadosOriginais.saldo_texto,
    dadosOriginais.saldo_num,
    dadosAtuais.cliente?.saldo,
    dadosAtuais.saldo,
    dadosAtuais.saldo_texto,
    dadosAtuais.saldo_num
  );

  const saldoNum = parseBRL(saldoOriginal);
  const saldoFormatado = formatarMoeda(saldoNum);

  const recomendacao = dadosOriginais.recomendacao ?? dadosAtuais.recomendacao ?? {};

  const statusRecomendacao = limparTexto(primeiroValor(
    recomendacao.status,
    dadosOriginais.status,
    dadosAtuais.status,
    "Não informado"
  ));

  const possuiRecomendacao = Boolean(
    recomendacao.possui_recomendacao ??
    dadosOriginais.possui_recomendacao ??
    dadosAtuais.possui_recomendacao
  );

  const produto = limparTexto(primeiroValor(
    recomendacao.produto,
    dadosOriginais.produto_recomendado,
    dadosAtuais.produto_recomendado,
    "Nenhum produto disponível"
  ));

  const perfilProduto = limparTexto(primeiroValor(
    recomendacao.perfil_produto,
    dadosOriginais.perfil_produto,
    dadosAtuais.perfil_produto,
    "Não aplicável"
  ));

  const valorMinimo = limparTexto(primeiroValor(
    recomendacao.valor_minimo,
    dadosOriginais.valor_minimo_texto,
    dadosAtuais.valor_minimo_texto,
    "Não aplicável"
  ));

  const rentabilidade = limparTexto(primeiroValor(
    recomendacao.rentabilidade_estimada,
    dadosOriginais.rentabilidade_estimada,
    dadosAtuais.rentabilidade_estimada,
    "Não aplicável"
  ));

  const quantidadeOpcoes = Number(primeiroValor(
    recomendacao.quantidade_opcoes_disponiveis,
    dadosOriginais.quantidade_opcoes_disponiveis,
    dadosAtuais.quantidade_opcoes_disponiveis,
    0
  ));

  const subject = limparTexto(primeiroValor(
    respostaAgente.subject,
    dadosOriginais.envio?.assunto,
    dadosAtuais.envio?.assunto,
    possuiRecomendacao
      ? `Recomendação de investimento para ${nome}`
      : `Análise de investimento para ${nome}`
  ));

  const textBody = limparTexto(primeiroValor(
    respostaAgente.text_body,
    dadosOriginais.envio?.mensagem_texto,
    dadosAtuais.envio?.mensagem_texto,
    `Olá, ${nome}.

Com base no seu perfil ${perfil} e no saldo disponível de ${saldoFormatado}, preparamos uma análise de investimento.

Produto: ${produto}
Valor mínimo: ${valorMinimo}
Rentabilidade estimada: ${rentabilidade}

Esta mensagem não representa promessa de ganho ou garantia de rentabilidade.`
  ));

  let htmlBody = limparTexto(primeiroValor(
    respostaAgente.html_body,
    dadosOriginais.envio?.mensagem_html,
    dadosAtuais.envio?.mensagem_html
  ));

  if (!htmlBody) {
    htmlBody = textoParaHtml(textBody);
  }

  const htmlBodyGmail = `
<div style="font-family: Arial, sans-serif; font-size: 14px; line-height: 1.6; color: #202124;">
  ${htmlBody.startsWith("<") ? htmlBody : textoParaHtml(htmlBody)}

  <hr style="border: none; border-top: 1px solid #e0e0e0; margin: 24px 0;">

  <p style="font-size: 12px; color: #666;">
    Mensagem gerada automaticamente pelo fluxo RPA + n8n.
    As informações apresentadas não constituem promessa de ganho ou garantia de rentabilidade.
  </p>
</div>
  `.trim();

  return {
    json: {
      to,
      email_detectado: emailDetectado,
      email_valido: emailValido(emailDetectado),

      subject,
      text_body: textBody,
      html_body: htmlBodyGmail,

      cliente_nome: nome,
      cliente_email: emailDetectado,
      cliente_perfil: perfil,
      cliente_saldo_original: saldoOriginal,
      cliente_saldo_num: saldoNum,
      cliente_saldo_formatado: saldoFormatado,

      recomendacao_status: statusRecomendacao,
      recomendacao_possui_recomendacao: possuiRecomendacao,
      recomendacao_produto: produto,
      recomendacao_perfil_produto: perfilProduto,
      recomendacao_valor_minimo: valorMinimo,
      recomendacao_rentabilidade_estimada: rentabilidade,
      recomendacao_quantidade_opcoes_disponiveis: quantidadeOpcoes,

      controle_data_processamento: dataProcessamento,
      controle_origem: "Fluxo RPA + n8n",
      controle_etapa: "Normalização para Gmail",
      controle_pronto_para_envio: Boolean(to && subject && htmlBodyGmail),
      controle_fonte_dados_originais: NOME_NO_DADOS_ORIGINAIS
    }
  };
});
